    public void Student_InheritsFromPerson_HasFullName()
    {
        // Arrange
        var student = new Student
        {
            LastName = "Alexander",
            FirstMidName = "Carson"
        };

        // Act & Assert
        Assert.AreEqual("Alexander, Carson", student.FullName);
    }

    [TestMethod]
    public void Enrollments_SetAndGet_ReturnsCollection()
    {
        // Arrange
        var student = new Student
        {
            Enrollments = new List<Enrollment>
            {
                new Enrollment { EnrollmentID = 1, CourseID = 1050 },
                new Enrollment { EnrollmentID = 2, CourseID = 4022 }
            }
        };

        // Act & Assert
        Assert.AreEqual(2, student.Enrollments.Count);
    }

