    public void Student_DefaultEnrollments_IsNull()
    {
        // Arrange
        var student = new Student();

        // Act & Assert
        Assert.IsNull(student.Enrollments);
    }

    [TestMethod]
    public void Student_SetAllProperties_AllPropertiesAccessible()
    {
        // Arrange
        var date = new DateTime(2020, 1, 15);
        var student = new Student
        {
            ID = 10,
            LastName = "Li",
            FirstMidName = "Yan",
            EnrollmentDate = date
        };

        // Act & Assert
        Assert.AreEqual(10, student.ID);
        Assert.AreEqual("Li", student.LastName);
        Assert.AreEqual("Yan", student.FirstMidName);
        Assert.AreEqual(date, student.EnrollmentDate);
        Assert.AreEqual("Li, Yan", student.FullName);
    }
}

