using Microsoft.VisualStudio.TestTools.UnitTesting;
using System.Collections.Generic;
using System.Linq;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class PaginatedListTests
{
    [TestMethod]
    public void Constructor_SetsPageIndex()
    {
        // Arrange
        var items = new List<string> { "a", "b", "c" };

        // Act
        var list = new PaginatedList<string>(items, 10, 2, 3);

        // Assert
        Assert.AreEqual(2, list.PageIndex);
    }

    [TestMethod]
    public void Constructor_CalculatesTotalPages_Correctly()
    {
        // Arrange
        var items = new List<string> { "a", "b", "c" };

        // Act - 10 items / 3 per page = 4 pages (ceiling)
        var list = new PaginatedList<string>(items, 10, 1, 3);

        // Assert
        Assert.AreEqual(4, list.TotalPages);
    }

    [TestMethod]
    [DataRow(10, 5, 2, DisplayName = "10 items, 5 per page = 2 pages")]
    [DataRow(10, 3, 4, DisplayName = "10 items, 3 per page = 4 pages")]
    [DataRow(1, 10, 1, DisplayName = "1 item, 10 per page = 1 page")]
    [DataRow(0, 10, 0, DisplayName = "0 items, 10 per page = 0 pages")]
    [DataRow(10, 10, 1, DisplayName = "10 items, 10 per page = 1 page")]
    [DataRow(11, 10, 2, DisplayName = "11 items, 10 per page = 2 pages")]
    public void Constructor_CalculatesTotalPages_VariousInputs(int count, int pageSize, int expectedPages)
    {
        // Arrange
        var items = new List<int>();

        // Act
        var list = new PaginatedList<int>(items, count, 1, pageSize);

        // Assert
        Assert.AreEqual(expectedPages, list.TotalPages);
    }

    [TestMethod]
    public void Constructor_AddsItemsToList()
    {
        // Arrange
        var items = new List<string> { "a", "b", "c" };

        // Act
        var list = new PaginatedList<string>(items, 3, 1, 10);

        // Assert
        Assert.AreEqual(3, list.Count);
        Assert.AreEqual("a", list[0]);
        Assert.AreEqual("b", list[1]);
        Assert.AreEqual("c", list[2]);
    }

    [TestMethod]
    public void HasPreviousPage_OnFirstPage_ReturnsFalse()
    {
        // Arrange
        var list = new PaginatedList<int>(new List<int>(), 20, 1, 10);

        // Act & Assert
        Assert.IsFalse(list.HasPreviousPage);
    }

    [TestMethod]
    public void HasPreviousPage_OnSecondPage_ReturnsTrue()
    {
        // Arrange
        var list = new PaginatedList<int>(new List<int>(), 20, 2, 10);

        // Act & Assert
        Assert.IsTrue(list.HasPreviousPage);
    }

    [TestMethod]
    public void HasNextPage_OnLastPage_ReturnsFalse()
    {
        // Arrange - 20 items, 10 per page = 2 pages total, on page 2
        var list = new PaginatedList<int>(new List<int>(), 20, 2, 10);

        // Act & Assert
        Assert.IsFalse(list.HasNextPage);
    }

    [TestMethod]
    public void HasNextPage_OnFirstPageOfMultiple_ReturnsTrue()
    {
        // Arrange - 20 items, 10 per page = 2 pages total, on page 1
        var list = new PaginatedList<int>(new List<int>(), 20, 1, 10);

        // Act & Assert
        Assert.IsTrue(list.HasNextPage);
    }

    [TestMethod]
    public void HasNextPage_SinglePage_ReturnsFalse()
    {
        // Arrange - 5 items, 10 per page = 1 page total, on page 1
        var list = new PaginatedList<int>(new List<int>(), 5, 1, 10);

        // Act & Assert
        Assert.IsFalse(list.HasNextPage);
    }

    [TestMethod]
    public void Create_ReturnsCorrectPage()
    {
        // Arrange
        var source = Enumerable.Range(1, 25).AsQueryable();

        // Act - page 2, 10 per page
        var list = PaginatedList<int>.Create(source, 2, 10);

        // Assert
        Assert.AreEqual(2, list.PageIndex);
        Assert.AreEqual(3, list.TotalPages);
        Assert.AreEqual(10, list.Count);
        Assert.AreEqual(11, list[0]); // Items 11-20 on page 2
        Assert.AreEqual(20, list[9]);
    }

    [TestMethod]
    public void Create_FirstPage_ReturnsFirstItems()
    {
        // Arrange
        var source = Enumerable.Range(1, 25).AsQueryable();

        // Act
        var list = PaginatedList<int>.Create(source, 1, 10);

        // Assert
        Assert.AreEqual(1, list.PageIndex);
        Assert.AreEqual(10, list.Count);
        Assert.AreEqual(1, list[0]);
        Assert.AreEqual(10, list[9]);
    }

    [TestMethod]
    public void Create_LastPage_ReturnsRemainingItems()
    {
        // Arrange
        var source = Enumerable.Range(1, 25).AsQueryable();

        // Act - page 3, 10 per page (only 5 items remaining)
        var list = PaginatedList<int>.Create(source, 3, 10);

        // Assert
        Assert.AreEqual(3, list.PageIndex);
        Assert.AreEqual(5, list.Count);
        Assert.AreEqual(21, list[0]);
        Assert.AreEqual(25, list[4]);
    }

    [TestMethod]
    public void Create_EmptySource_ReturnsEmptyList()
    {
        // Arrange
        var source = Enumerable.Empty<int>().AsQueryable();

        // Act
        var list = PaginatedList<int>.Create(source, 1, 10);

        // Assert
        Assert.AreEqual(0, list.Count);
        Assert.AreEqual(0, list.TotalPages);
    }

    [TestMethod]
    public void Create_ExactlyOnePage_HasNoNextOrPrevious()
    {
        // Arrange
        var source = Enumerable.Range(1, 10).AsQueryable();

        // Act
        var list = PaginatedList<int>.Create(source, 1, 10);

        // Assert
        Assert.AreEqual(1, list.TotalPages);
        Assert.IsFalse(list.HasPreviousPage);
        Assert.IsFalse(list.HasNextPage);
        Assert.AreEqual(10, list.Count);
    }
}

