using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Models;
using ContosoUniversity.Services;

namespace ContosoUniversity.Tests.Services;

[TestClass]
public sealed class NotificationServiceTests
{
    private NotificationService _service;

    [TestInitialize]
    public void Setup()
    {
        _service = new NotificationService();
        // Drain any leftover notifications from the static queue
        while (_service.ReceiveNotification() != null) { }
    }

    [TestCleanup]
    public void Cleanup()
    {
        _service?.Dispose();
    }

    [TestMethod]
    public void SendNotification_WithDisplayName_EnqueuesNotification()
    {
        // Act
        _service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "Admin");

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("Student", notification.EntityType);
        Assert.AreEqual("1", notification.EntityId);
        Assert.AreEqual("CREATE", notification.Operation);
        Assert.AreEqual("Admin", notification.CreatedBy);
        Assert.IsFalse(notification.IsRead);
    }

    [TestMethod]
    public void SendNotification_WithoutDisplayName_EnqueuesNotification()
    {
        // Act
        _service.SendNotification("Course", "1050", EntityOperation.UPDATE, "System");

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("Course", notification.EntityType);
        Assert.AreEqual("1050", notification.EntityId);
        Assert.AreEqual("UPDATE", notification.Operation);
    }

    [TestMethod]
    public void SendNotification_WithNullUserName_DefaultsToSystem()
    {
        // Act
        _service.SendNotification("Department", "1", EntityOperation.DELETE, null);

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("System", notification.CreatedBy);
    }

    [TestMethod]
    public void SendNotification_WithoutUserName_DefaultsToSystem()
    {
        // Act
        _service.SendNotification("Department", "1", EntityOperation.CREATE);

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("System", notification.CreatedBy);
    }

    [TestMethod]
    public void SendNotification_CreateOperation_GeneratesCorrectMessage()
    {
        // Act
        _service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE);

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("New Student 'John Doe' has been created", notification.Message);
    }

    [TestMethod]
    public void SendNotification_UpdateOperation_GeneratesCorrectMessage()
    {
        // Act
        _service.SendNotification("Course", "1050", "Chemistry", EntityOperation.UPDATE);

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("Course 'Chemistry' has been updated", notification.Message);
    }

    [TestMethod]
    public void SendNotification_DeleteOperation_GeneratesCorrectMessage()
    {
        // Act
        _service.SendNotification("Department", "3", "Engineering", EntityOperation.DELETE);

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("Department 'Engineering' has been deleted", notification.Message);
    }

    [TestMethod]
    public void SendNotification_WithoutDisplayName_UsesIdInMessage()
    {
        // Act
        _service.SendNotification("Instructor", "42", EntityOperation.CREATE);

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("New Instructor (ID: 42) has been created", notification.Message);
    }

    [TestMethod]
    public void SendNotification_UpdateWithoutDisplayName_UsesIdInMessage()
    {
        // Act
        _service.SendNotification("Instructor", "42", EntityOperation.UPDATE);

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("Instructor (ID: 42) has been updated", notification.Message);
    }

    [TestMethod]
    public void SendNotification_DeleteWithoutDisplayName_UsesIdInMessage()
    {
        // Act
        _service.SendNotification("Student", "7", EntityOperation.DELETE);

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("Student (ID: 7) has been deleted", notification.Message);
    }

    [TestMethod]
    public void ReceiveNotification_WhenEmpty_ReturnsNull()
    {
        // Act
        var result = _service.ReceiveNotification();

        // Assert
        Assert.IsNull(result);
    }

    [TestMethod]
    public void ReceiveNotification_MultipleMessages_ReturnsFIFO()
    {
        // Arrange
        _service.SendNotification("Student", "1", "First", EntityOperation.CREATE);
        _service.SendNotification("Course", "2", "Second", EntityOperation.UPDATE);
        _service.SendNotification("Department", "3", "Third", EntityOperation.DELETE);

        // Act & Assert - FIFO order
        var first = _service.ReceiveNotification();
        Assert.AreEqual("Student", first.EntityType);

        var second = _service.ReceiveNotification();
        Assert.AreEqual("Course", second.EntityType);

        var third = _service.ReceiveNotification();
        Assert.AreEqual("Department", third.EntityType);

        var fourth = _service.ReceiveNotification();
        Assert.IsNull(fourth);
    }

    [TestMethod]
    public void MarkAsRead_DoesNotThrow()
    {
        // Act - MarkAsRead is a no-op for in-memory implementation
        _service.MarkAsRead(1);
        _service.MarkAsRead(999);

        // Assert - just verify no exception
        Assert.IsTrue(true);
    }

    [TestMethod]
    public void SendNotification_SetsCreatedAt()
    {
        // Arrange
        var before = System.DateTime.Now;

        // Act
        _service.SendNotification("Test", "1", EntityOperation.CREATE);

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.IsTrue(notification.CreatedAt >= before);
        Assert.IsTrue(notification.CreatedAt <= System.DateTime.Now);
    }

    [TestMethod]
    public void SendNotification_SetsIsReadToFalse()
    {
        // Act
        _service.SendNotification("Test", "1", EntityOperation.CREATE);

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.IsFalse(notification.IsRead);
    }

    [TestMethod]
    public void Dispose_DoesNotThrow()
    {
        // Act
        var service = new NotificationService();
        service.Dispose();

        // Assert - just verify no exception
        Assert.IsTrue(true);
    }

    [TestMethod]
    public void SendNotification_WithEmptyDisplayName_UsesIdInMessage()
    {
        // Act
        _service.SendNotification("Student", "5", "", EntityOperation.CREATE);

        // Assert - empty string is treated as no display name
        var notification = _service.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("New Student (ID: 5) has been created", notification.Message);
    }

    [TestMethod]
    public void SendNotification_WithWhitespaceDisplayName_UsesIdInMessage()
    {
        // Act
        _service.SendNotification("Student", "5", "   ", EntityOperation.CREATE);

        // Assert - whitespace is treated as no display name
        var notification = _service.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("New Student (ID: 5) has been created", notification.Message);
    }
}

