using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Mvc;
using System;
using System.Linq;

namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class StudentsControllerTests
{
    private SchoolContext _context;
    private StudentsController _controller;

    [TestInitialize]
    public void Setup()
    {
        _context = TestDbContextFactory.Create();
        _controller = new StudentsController(_context);
    }

    [TestCleanup]
    public void Cleanup()
    {
        _controller?.Dispose();
        _context?.Dispose();
    }

    private Student AddStudent(string lastName = "Doe", string firstName = "John", DateTime? enrollmentDate = null)
    {
        var student = new Student
        {
            LastName = lastName,
            FirstMidName = firstName,
            EnrollmentDate = enrollmentDate ?? new DateTime(2023, 9, 1)
        };
        _context.Students.Add(student);
        _context.SaveChanges();
        return student;
    }

    #region Index Tests

    [TestMethod]
    public void Index_ReturnsViewResult()
    {
        // Arrange
        AddStudent();

        // Act
        var result = _controller.Index(null, null, null, null);

        // Assert
        Assert.IsInstanceOfType<ViewResult>(result);
    }

    [TestMethod]
    public void Index_DefaultSort_OrdersByLastNameAscending()
    {
        // Arrange
        AddStudent("Zebra", "Alice");
        AddStudent("Alpha", "Bob");
        AddStudent("Middle", "Carol");

        // Act
        var result = _controller.Index(null, null, null, null) as ViewResult;
        var model = result.Model as PaginatedList<Student>;

        // Assert
        Assert.IsNotNull(model);
        Assert.AreEqual(3, model.Count);
        Assert.AreEqual("Alpha", model[0].LastName);
        Assert.AreEqual("Middle", model[1].LastName);
        Assert.AreEqual("Zebra", model[2].LastName);
    }

    [TestMethod]
    public void Index_NameDescSort_OrdersByLastNameDescending()
    {
        // Arrange
        AddStudent("Alpha", "Alice");
        AddStudent("Zebra", "Bob");

        // Act
        var result = _controller.Index("name_desc", null, null, null) as ViewResult;
        var model = result.Model as PaginatedList<Student>;

        // Assert
        Assert.IsNotNull(model);
        Assert.AreEqual("Zebra", model[0].LastName);
        Assert.AreEqual("Alpha", model[1].LastName);
    }

    [TestMethod]
    public void Index_DateSort_OrdersByEnrollmentDateAscending()
    {
        // Arrange
        AddStudent("B", "B", new DateTime(2024, 1, 1));
        AddStudent("A", "A", new DateTime(2020, 1, 1));

        // Act
        var result = _controller.Index("Date", null, null, null) as ViewResult;
        var model = result.Model as PaginatedList<Student>;

        // Assert
        Assert.IsNotNull(model);
        Assert.AreEqual("A", model[0].LastName);
        Assert.AreEqual("B", model[1].LastName);
    }

    [TestMethod]
    public void Index_DateDescSort_OrdersByEnrollmentDateDescending()
    {
        // Arrange
        AddStudent("A", "A", new DateTime(2020, 1, 1));
        AddStudent("B", "B", new DateTime(2024, 1, 1));

        // Act
        var result = _controller.Index("date_desc", null, null, null) as ViewResult;
        var model = result.Model as PaginatedList<Student>;

        // Assert
        Assert.IsNotNull(model);
        Assert.AreEqual("B", model[0].LastName);
        Assert.AreEqual("A", model[1].LastName);
    }

    [TestMethod]
    public void Index_SearchByLastName_FiltersCorrectly()
    {
        // Arrange
        AddStudent("Alexander", "Carson");
        AddStudent("Alonso", "Meredith");
        AddStudent("Barzdukas", "Gytis");

        // Act
        var result = _controller.Index(null, null, "Al", null) as ViewResult;
        var model = result.Model as PaginatedList<Student>;

        // Assert
        Assert.IsNotNull(model);
        Assert.AreEqual(2, model.Count);
        Assert.IsTrue(model.All(s => s.LastName.Contains("Al")));
    }

    [TestMethod]
    public void Index_SearchByFirstName_FiltersCorrectly()
    {
        // Arrange
        AddStudent("Smith", "Carson");
        AddStudent("Jones", "Meredith");

        // Act
        var result = _controller.Index(null, null, "Carson", null) as ViewResult;
        var model = result.Model as PaginatedList<Student>;

        // Assert
        Assert.IsNotNull(model);
        Assert.AreEqual(1, model.Count);
        Assert.AreEqual("Smith", model[0].LastName);
    }

    [TestMethod]
    public void Index_SearchString_ResetsPageToOne()
    {
        // Arrange
        AddStudent();

        // Act
        var result = _controller.Index(null, null, "Doe", null) as ViewResult;

        // Assert - ViewBag.CurrentFilter should be set
        Assert.AreEqual("Doe", _controller.ViewBag.CurrentFilter);
    }

    [TestMethod]
    public void Index_NoSearchString_UsesCurrentFilter()
    {
        // Arrange
        AddStudent("TestFilter", "Name");

        // Act
        var result = _controller.Index(null, "TestFilter", null, null) as ViewResult;

        // Assert
        Assert.AreEqual("TestFilter", _controller.ViewBag.CurrentFilter);
    }

    [TestMethod]
    public void Index_SetsViewBagSortParameters()
    {
        // Act
        var result = _controller.Index(null, null, null, null);

        // Assert
        Assert.AreEqual("name_desc", _controller.ViewBag.NameSortParm);
        Assert.AreEqual("Date", _controller.ViewBag.DateSortParm);
    }

