using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Mvc;
using System;
using System.Linq;

namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class DepartmentsControllerTests
{
    private SchoolContext _context;
    private DepartmentsController _controller;

    [TestInitialize]
    public void Setup()
    {
        _context = TestDbContextFactory.Create();
        _controller = new DepartmentsController(_context);
    }

    [TestCleanup]
    public void Cleanup()
    {
        _controller?.Dispose();
        _context?.Dispose();
    }

    private Instructor AddInstructor(string lastName = "Smith", string firstName = "John")
    {
        var instructor = new Instructor
        {
            LastName = lastName,
            FirstMidName = firstName,
            HireDate = new DateTime(2000, 1, 1)
        };
        _context.Instructors.Add(instructor);
        _context.SaveChanges();
        return instructor;
    }

    private Department AddDepartment(string name = "Engineering", decimal budget = 350000m, int? instructorId = null)
    {
        var department = new Department
        {
            Name = name,
            Budget = budget,
            StartDate = new DateTime(2007, 9, 1),
            InstructorID = instructorId
        };
        _context.Departments.Add(department);
        _context.SaveChanges();
        return department;
    }

    #region Index Tests

    [TestMethod]
    public void Index_ReturnsViewResult()
    {
        // Act
        var result = _controller.Index();

        // Assert
        Assert.IsInstanceOfType<ViewResult>(result);
    }

    [TestMethod]
    public void Index_ReturnsAllDepartments()
    {
        // Arrange
        AddDepartment("English");
        AddDepartment("Mathematics");
        AddDepartment("Engineering");

        // Act
        var result = _controller.Index() as ViewResult;
        var model = result.Model as System.Collections.Generic.List<Department>;

        // Assert
        Assert.IsNotNull(model);
        Assert.AreEqual(3, model.Count);
    }

    #endregion

    #region Details Tests

    [TestMethod]
    public void Details_NullId_ReturnsBadRequest()
    {
        // Act
        var result = _controller.Details(null);

        // Assert
        Assert.IsInstanceOfType<StatusCodeResult>(result);
        Assert.AreEqual(400, ((StatusCodeResult)result).StatusCode);
    }

    [TestMethod]
    public void Details_InvalidId_ReturnsNotFound()
    {
        // Act
        var result = _controller.Details(9999);

        // Assert
        Assert.IsInstanceOfType<NotFoundResult>(result);
    }

    [TestMethod]
    public void Details_ValidId_ReturnsViewWithDepartment()
    {
        // Arrange
        var dept = AddDepartment("Engineering");

        // Act
        var result = _controller.Details(dept.DepartmentID) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as Department;
        Assert.IsNotNull(model);
        Assert.AreEqual("Engineering", model.Name);
    }

    #endregion

    #region Create GET Tests

    [TestMethod]
    public void Create_GET_ReturnsViewResult()
    {
        // Arrange - add instructors for dropdown
