using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Hosting;
using Microsoft.Extensions.Logging;
using Moq;
using System;
using System.Collections.Generic;
using System.Linq;

namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class CoursesControllerTests
{
    private SchoolContext _context;
    private CoursesController _controller;
    private Mock<IWebHostEnvironment> _envMock;
    private Mock<ILogger<CoursesController>> _loggerMock;

    [TestInitialize]
    public void Setup()
    {
        _context = TestDbContextFactory.Create();
        _envMock = new Mock<IWebHostEnvironment>();
        _envMock.Setup(e => e.WebRootPath).Returns(System.IO.Path.GetTempPath());
        _envMock.Setup(e => e.ContentRootPath).Returns(System.IO.Path.GetTempPath());
        _loggerMock = new Mock<ILogger<CoursesController>>();
        _controller = new CoursesController(_context, _envMock.Object, _loggerMock.Object);
    }

    [TestCleanup]
    public void Cleanup()
    {
        _controller?.Dispose();
        _context?.Dispose();
    }

    private Department AddDepartment(string name = "Engineering")
    {
        var dept = new Department
        {
            Name = name,
            Budget = 350000m,
            StartDate = new DateTime(2007, 9, 1)
        };
        _context.Departments.Add(dept);
        _context.SaveChanges();
        return dept;
    }

    private Course AddCourse(int courseId = 1050, string title = "Chemistry", int credits = 3, int? departmentId = null)
    {
        if (departmentId == null)
        {
            var dept = AddDepartment();
            departmentId = dept.DepartmentID;
        }
        var course = new Course
        {
            CourseID = courseId,
            Title = title,
            Credits = credits,
            DepartmentID = departmentId.Value
        };
        _context.Courses.Add(course);
        _context.SaveChanges();
        return course;
    }

    #region Index Tests

    [TestMethod]
    public void Index_ReturnsViewResult()
    {
        // Act
        var result = _controller.Index();

        // Assert
        Assert.IsInstanceOfType<ViewResult>(result);
    }

    [TestMethod]
    public void Index_ReturnsAllCourses()
    {
        // Arrange
        var dept = AddDepartment();
        AddCourse(1050, "Chemistry", 3, dept.DepartmentID);
        AddCourse(1045, "Calculus", 4, dept.DepartmentID);

        // Act
        var result = _controller.Index() as ViewResult;
        var model = result.Model as List<Course>;

        // Assert
        Assert.IsNotNull(model);
        Assert.AreEqual(2, model.Count);
    }

    [TestMethod]
    public void Index_CoursesIncludeDepartment()
    {
        // Arrange
        var dept = AddDepartment("Mathematics");
        AddCourse(1045, "Calculus", 4, dept.DepartmentID);

        // Act
        var result = _controller.Index() as ViewResult;
        var model = result.Model as List<Course>;

        // Assert
        Assert.IsNotNull(model);
        Assert.AreEqual(1, model.Count);
        Assert.IsNotNull(model[0].Department);
        Assert.AreEqual("Mathematics", model[0].Department.Name);
    }

    #endregion

    #region Details Tests

    [TestMethod]
    public void Details_NullId_ReturnsBadRequest()
    {
        // Act
        var result = _controller.Details(null);

        // Assert
        Assert.IsInstanceOfType<StatusCodeResult>(result);
        Assert.AreEqual(400, ((StatusCodeResult)result).StatusCode);
    }

    [TestMethod]
    public void Details_ValidId_ReturnsViewWithCourse()
    {
        // Arrange
        var course = AddCourse(1050, "Chemistry");

        // Act
        var result = _controller.Details(course.CourseID) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as Course;
        Assert.IsNotNull(model);
        Assert.AreEqual("Chemistry", model.Title);
        Assert.AreEqual(1050, model.CourseID);
    }

    #endregion

    #region Create GET Tests

    [TestMethod]
    public void Create_GET_ReturnsViewResult()
    {
        // Arrange
        AddDepartment();

        // Act
        var result = _controller.Create();

        // Assert
        Assert.IsInstanceOfType<ViewResult>(result);
    }

    [TestMethod]
    public void Create_GET_ReturnsCourseModel()
    {
        // Arrange
        AddDepartment();

        // Act
        var result = _controller.Create() as ViewResult;
        var model = result.Model as Course;

        // Assert
        Assert.IsNotNull(model);
    }

    [TestMethod]
    public void Create_GET_SetsDepartmentDropdown()
    {
        // Arrange
        AddDepartment("Engineering");

        // Act
        _controller.Create();

        // Assert
        Assert.IsNotNull(_controller.ViewBag.DepartmentID);
    }

    #endregion

    #region Create POST Tests

    [TestMethod]
    public void Create_POST_ValidCourse_RedirectsToIndex()
    {
        // Arrange
        var dept = AddDepartment();
        var course = new Course
        {
            CourseID = 9999,
            Title = "NewCourse",
            Credits = 3,
            DepartmentID = dept.DepartmentID
        };

        // Act
        var result = _controller.Create(course, null);

        // Assert
        Assert.IsInstanceOfType<RedirectToActionResult>(result);
        Assert.AreEqual("Index", ((RedirectToActionResult)result).ActionName);
