using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using Microsoft.AspNetCore.Mvc;
using System;
using System.Collections.Generic;
using System.Linq;

namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class InstructorsControllerTests
{
    private SchoolContext _context;
    private InstructorsController _controller;

    [TestInitialize]
    public void Setup()
    {
        _context = TestDbContextFactory.Create();
        _controller = new InstructorsController(_context);
    }

    [TestCleanup]
    public void Cleanup()
    {
        _controller?.Dispose();
        _context?.Dispose();
    }

    private Instructor AddInstructor(string lastName = "Smith", string firstName = "John",
        DateTime? hireDate = null, string officeLocation = null, List<int> courseIds = null)
    {
        var instructor = new Instructor
        {
            LastName = lastName,
            FirstMidName = firstName,
            HireDate = hireDate ?? new DateTime(2000, 1, 1),
            CourseAssignments = new List<CourseAssignment>()
        };

        if (officeLocation != null)
        {
            instructor.OfficeAssignment = new OfficeAssignment { Location = officeLocation };
        }

        _context.Instructors.Add(instructor);
        _context.SaveChanges();

        if (courseIds != null)
        {
            foreach (var courseId in courseIds)
            {
                _context.CourseAssignments.Add(new CourseAssignment
                {
                    InstructorID = instructor.ID,
                    CourseID = courseId
                });
            }
            _context.SaveChanges();
        }

        return instructor;
    }

    private Department AddDepartment(string name = "Engineering", int? instructorId = null)
    {
        var dept = new Department
        {
            Name = name,
            Budget = 350000m,
            StartDate = new DateTime(2007, 9, 1),
            InstructorID = instructorId
        };
        _context.Departments.Add(dept);
        _context.SaveChanges();
        return dept;
    }

    private Course AddCourse(int courseId, string title = "TestCourse", int? deptId = null)
    {
        if (deptId == null)
        {
            var dept = AddDepartment();
            deptId = dept.DepartmentID;
        }
        var course = new Course
        {
            CourseID = courseId,
            Title = title,
            Credits = 3,
            DepartmentID = deptId.Value
        };
        _context.Courses.Add(course);
        _context.SaveChanges();
        return course;
    }

    #region Index Tests

    [TestMethod]
    public void Index_ReturnsViewResult()
    {
        // Act
        var result = _controller.Index(null, null);

        // Assert
        Assert.IsInstanceOfType<ViewResult>(result);
    }

    [TestMethod]
    public void Index_ReturnsInstructorIndexData()
    {
        // Arrange
        AddInstructor("Abercrombie", "Kim");
        AddInstructor("Fakhouri", "Fadi");

        // Act
        var result = _controller.Index(null, null) as ViewResult;
        var model = result.Model as InstructorIndexData;

        // Assert
        Assert.IsNotNull(model);
        Assert.IsNotNull(model.Instructors);
        Assert.AreEqual(2, model.Instructors.Count());
    }

    [TestMethod]
    public void Index_OrdersByLastName()
    {
        // Arrange
        AddInstructor("Zheng", "Roger");
        AddInstructor("Abercrombie", "Kim");

        // Act
        var result = _controller.Index(null, null) as ViewResult;
        var model = result.Model as InstructorIndexData;
        var instructors = model.Instructors.ToList();

        // Assert
        Assert.AreEqual("Abercrombie", instructors[0].LastName);
        Assert.AreEqual("Zheng", instructors[1].LastName);
    }

    [TestMethod]
    public void Index_WithInstructorId_SetsCourses()
    {
        // Arrange
        var dept = AddDepartment();
        var course = AddCourse(1050, "Chemistry", dept.DepartmentID);
        var instructor = AddInstructor("Abercrombie", "Kim", courseIds: new List<int> { course.CourseID });

        // Act
        var result = _controller.Index(instructor.ID, null) as ViewResult;
        var model = result.Model as InstructorIndexData;

        // Assert
        Assert.IsNotNull(model.Courses);
        Assert.AreEqual(1, model.Courses.Count());
        Assert.AreEqual("Chemistry", model.Courses.First().Title);
    }

    [TestMethod]
    public void Index_WithInstructorId_SetsViewBagInstructorID()
    {
        // Arrange
        var instructor = AddInstructor("Test", "Instructor");

        // Act
        _controller.Index(instructor.ID, null);

        // Assert
        Assert.AreEqual(instructor.ID, _controller.ViewBag.InstructorID);
    }

    #endregion

    #region Details Tests

    [TestMethod]
    public void Details_NullId_ReturnsBadRequest()
    {
        // Act
        var result = _controller.Details(null);

        // Assert
        Assert.IsInstanceOfType<StatusCodeResult>(result);
        Assert.AreEqual(400, ((StatusCodeResult)result).StatusCode);
    }

    [TestMethod]
    public void Details_InvalidId_ReturnsNotFound()
    {
        // Act
        var result = _controller.Details(9999);

        // Assert
        Assert.IsInstanceOfType<NotFoundResult>(result);
    }

    [TestMethod]
    public void Details_ValidId_ReturnsViewWithInstructor()
    {
        // Arrange
        var instructor = AddInstructor("Abercrombie", "Kim");

        // Act
        var result = _controller.Details(instructor.ID) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as Instructor;
        Assert.IsNotNull(model);
        Assert.AreEqual("Abercrombie", model.LastName);
        Assert.AreEqual("Kim", model.FirstMidName);
    }

    #endregion

    #region Create GET Tests

    [TestMethod]
    public void Create_GET_ReturnsViewResult()
    {
        // Act
        var result = _controller.Create();

        // Assert
        Assert.IsInstanceOfType<ViewResult>(result);
    }

    [TestMethod]
    public void Create_GET_ReturnsInstructorWithEmptyCourseAssignments()
    {
        // Act
        var result = _controller.Create() as ViewResult;
        var model = result.Model as Instructor;

        // Assert
        Assert.IsNotNull(model);
        Assert.IsNotNull(model.CourseAssignments);
        Assert.AreEqual(0, model.CourseAssignments.Count);
    }

    #endregion

    #region Create POST Tests

    [TestMethod]
    public void Create_POST_ValidInstructor_RedirectsToIndex()
    {
        // Arrange
        var instructor = new Instructor
        {
            LastName = "NewInstructor",
            FirstMidName = "Test",
            HireDate = new DateTime(2023, 1, 1)
        };

        // Act
        var result = _controller.Create(instructor, null);

        // Assert
        Assert.IsInstanceOfType<RedirectToActionResult>(result);
        Assert.AreEqual("Index", ((RedirectToActionResult)result).ActionName);
    }

    [TestMethod]
    public void Create_POST_ValidInstructor_AddsToDatabase()
    {
        // Arrange
        var instructor = new Instructor
        {
            LastName = "NewInstructor",
            FirstMidName = "Test",
            HireDate = new DateTime(2023, 1, 1)
        };

        // Act
        _controller.Create(instructor, null);

        // Assert
        var saved = _context.Instructors.Single(i => i.LastName == "NewInstructor");
        Assert.AreEqual("NewInstructor", saved.LastName);
        Assert.AreEqual("Test", saved.FirstMidName);
    }

    [TestMethod]
    public void Create_POST_WithSelectedCourses_CreatesCourseAssignments()
    {
        // Arrange
        var dept = AddDepartment();
        var course1 = AddCourse(1050, "Chemistry", dept.DepartmentID);
        var course2 = AddCourse(1045, "Calculus", dept.DepartmentID);

        var instructor = new Instructor
        {
            LastName = "WithCourses",
            FirstMidName = "Test",
            HireDate = new DateTime(2023, 1, 1)
        };

        // Act
        _controller.Create(instructor, new[] { course1.CourseID.ToString(), course2.CourseID.ToString() });

        // Assert
        var saved = _context.Instructors
            .Where(i => i.LastName == "WithCourses")
            .Single();
        // Reload course assignments
        var assignments = _context.CourseAssignments.Where(ca => ca.InstructorID == saved.ID).ToList();
        Assert.AreEqual(2, assignments.Count);
    }

    [TestMethod]
    public void Create_POST_InvalidModelState_ReturnsView()
    {
        // Arrange
        _controller.ModelState.AddModelError("LastName", "Required");
        var instructor = new Instructor
        {
            HireDate = new DateTime(2023, 1, 1),
            CourseAssignments = new List<CourseAssignment>()
        };

        // Act
        var result = _controller.Create(instructor, null);

        // Assert
        Assert.IsInstanceOfType<ViewResult>(result);
    }

    #endregion

    #region Edit GET Tests

    [TestMethod]
    public void Edit_GET_NullId_ReturnsBadRequest()
    {
        // Act
        var result = _controller.Edit(null);

        // Assert
        Assert.IsInstanceOfType<StatusCodeResult>(result);
        Assert.AreEqual(400, ((StatusCodeResult)result).StatusCode);
    }

    [TestMethod]
    public void Edit_GET_ValidId_ReturnsViewWithInstructor()
    {
        // Arrange
        var instructor = AddInstructor("EditMe", "Test");

        // Act
        var result = _controller.Edit(instructor.ID) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as Instructor;
        Assert.IsNotNull(model);
        Assert.AreEqual("EditMe", model.LastName);
    }

    [TestMethod]
    public void Edit_GET_ValidId_PopulatesAssignedCourseData()
    {
        // Arrange
        var dept = AddDepartment();
        AddCourse(1050, "Chemistry", dept.DepartmentID);
        var instructor = AddInstructor("Test", "Instructor");

        // Act
        _controller.Edit(instructor.ID);

        // Assert
        Assert.IsNotNull(_controller.ViewBag.Courses);
        var assignedCourseData = _controller.ViewBag.Courses as List<AssignedCourseData>;
        Assert.IsNotNull(assignedCourseData);
        Assert.IsTrue(assignedCourseData.Count > 0);
    }

    #endregion

    #region Delete GET Tests

    [TestMethod]
    public void Delete_GET_NullId_ReturnsBadRequest()
    {
        // Act
        var result = _controller.Delete(null);

        // Assert
        Assert.IsInstanceOfType<StatusCodeResult>(result);
        Assert.AreEqual(400, ((StatusCodeResult)result).StatusCode);
    }

    [TestMethod]
    public void Delete_GET_InvalidId_ReturnsNotFound()
    {
        // Act
        var result = _controller.Delete(9999);

        // Assert
        Assert.IsInstanceOfType<NotFoundResult>(result);
    }

    [TestMethod]
    public void Delete_GET_ValidId_ReturnsViewWithInstructor()
    {
        // Arrange
        var instructor = AddInstructor("DeleteMe", "Test");

        // Act
        var result = _controller.Delete(instructor.ID) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as Instructor;
        Assert.IsNotNull(model);
        Assert.AreEqual("DeleteMe", model.LastName);
    }

    #endregion

    #region Delete POST Tests

    [TestMethod]
    public void DeleteConfirmed_ValidId_RedirectsToIndex()
    {
        // Arrange
        var instructor = AddInstructor("DeleteMe", "Test");

        // Act
        var result = _controller.DeleteConfirmed(instructor.ID);

        // Assert
        Assert.IsInstanceOfType<RedirectToActionResult>(result);
        Assert.AreEqual("Index", ((RedirectToActionResult)result).ActionName);
    }

    [TestMethod]
    public void DeleteConfirmed_ValidId_RemovesFromDatabase()
    {
        // Arrange
        var instructor = AddInstructor("DeleteMe", "Test");
        var id = instructor.ID;

        // Act
        _controller.DeleteConfirmed(id);

        // Assert
        Assert.IsNull(_context.Instructors.Find(id));
    }

    [TestMethod]
    public void DeleteConfirmed_InstructorAsDepartmentAdmin_NullsDepartmentInstructorId()
    {
        // Arrange
        var instructor = AddInstructor("Admin", "Dept");
        var dept = AddDepartment("TestDept", instructor.ID);

        // Act
        _controller.DeleteConfirmed(instructor.ID);

        // Assert
