using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using System.Linq;

namespace ContosoUniversity.Tests.Data;

[TestClass]
public sealed class DbInitializerTests
{
    private SchoolContext _context;

    [TestInitialize]
    public void Setup()
    {
        _context = TestDbContextFactory.Create();
    }

    [TestCleanup]
    public void Cleanup()
    {
        _context?.Dispose();
    }

    [TestMethod]
    public void Initialize_EmptyDatabase_SeedsStudents()
    {
        // Act
        DbInitializer.Initialize(_context);

        // Assert
        Assert.AreEqual(8, _context.Students.Count());
    }

    [TestMethod]
    public void Initialize_EmptyDatabase_SeedsInstructors()
    {
        // Act
        DbInitializer.Initialize(_context);

        // Assert
        Assert.AreEqual(5, _context.Instructors.Count());
    }

    [TestMethod]
    public void Initialize_EmptyDatabase_SeedsDepartments()
    {
        // Act
        DbInitializer.Initialize(_context);

        // Assert
        Assert.AreEqual(4, _context.Departments.Count());
    }

    [TestMethod]
    public void Initialize_EmptyDatabase_SeedsCourses()
    {
        // Act
        DbInitializer.Initialize(_context);

        // Assert
        Assert.AreEqual(7, _context.Courses.Count());
    }

    [TestMethod]
    public void Initialize_EmptyDatabase_SeedsOfficeAssignments()
    {
        // Act
        DbInitializer.Initialize(_context);

        // Assert
        Assert.AreEqual(3, _context.OfficeAssignments.Count());
    }

    [TestMethod]
    public void Initialize_EmptyDatabase_SeedsCourseAssignments()
    {
        // Act
        DbInitializer.Initialize(_context);

        // Assert
        Assert.AreEqual(8, _context.CourseAssignments.Count());
    }

    [TestMethod]
    public void Initialize_EmptyDatabase_SeedsEnrollments()
    {
        // Act
        DbInitializer.Initialize(_context);

        // Assert
        Assert.AreEqual(11, _context.Enrollments.Count());
    }

    [TestMethod]
    public void Initialize_AlreadySeeded_DoesNotDuplicate()
    {
        // Arrange - Initialize once
        DbInitializer.Initialize(_context);
        var initialStudentCount = _context.Students.Count();

        // Act - Initialize again
        DbInitializer.Initialize(_context);

        // Assert - Should not add more students
        Assert.AreEqual(initialStudentCount, _context.Students.Count());
    }

    [TestMethod]
    public void Initialize_SeedsCorrectStudentData()
    {
        // Act
        DbInitializer.Initialize(_context);

        // Assert - Verify specific student data
        var carson = _context.Students.Single(s => s.LastName == "Alexander");
        Assert.AreEqual("Carson", carson.FirstMidName);

        var meredith = _context.Students.Single(s => s.LastName == "Alonso");
        Assert.AreEqual("Meredith", meredith.FirstMidName);
    }

    [TestMethod]
    public void Initialize_SeedsCorrectDepartmentData()
    {
        // Act
        DbInitializer.Initialize(_context);

        // Assert
        var english = _context.Departments.Single(d => d.Name == "English");
        Assert.AreEqual(350000m, english.Budget);

        var math = _context.Departments.Single(d => d.Name == "Mathematics");
        Assert.AreEqual(100000m, math.Budget);
    }

    [TestMethod]
    public void Initialize_SeedsCorrectCourseData()
    {
        // Act
        DbInitializer.Initialize(_context);

        // Assert
        var chemistry = _context.Courses.Single(c => c.CourseID == 1050);
        Assert.AreEqual("Chemistry", chemistry.Title);
        Assert.AreEqual(3, chemistry.Credits);

        var calculus = _context.Courses.Single(c => c.CourseID == 1045);
        Assert.AreEqual("Calculus", calculus.Title);
        Assert.AreEqual(4, calculus.Credits);
    }

    [TestMethod]
    public void Initialize_SeedsEnrollmentsWithGrades()
    {
        // Act
        DbInitializer.Initialize(_context);

        // Assert - Carson Alexander enrolled in Chemistry with grade A
        var carson = _context.Students.Single(s => s.LastName == "Alexander");
        var chemistryEnrollment = _context.Enrollments
            .Single(e => e.StudentID == carson.ID && e.CourseID == 1050);
        Assert.AreEqual(Grade.A, chemistryEnrollment.Grade);
    }

    [TestMethod]
    public void Initialize_SeedsEnrollmentsWithNullGrades()
    {
        // Act
        DbInitializer.Initialize(_context);

        // Assert - Arturo Anand enrolled in Chemistry with no grade
        var arturo = _context.Students.Single(s => s.LastName == "Anand");
        var chemistryEnrollment = _context.Enrollments
            .Single(e => e.StudentID == arturo.ID && e.CourseID == 1050);
        Assert.IsNull(chemistryEnrollment.Grade);
    }

    [TestMethod]
    public void Initialize_SeedsOfficeAssignmentsCorrectly()
    {
        // Act
        DbInitializer.Initialize(_context);

        // Assert
        var fakhouri = _context.Instructors.Single(i => i.LastName == "Fakhouri");
        var office = _context.OfficeAssignments.Single(o => o.InstructorID == fakhouri.ID);
        Assert.AreEqual("Smith 17", office.Location);
    }
}

